/**
 * Calculates the payout owed to a partner for a given transaction.
 *
 * Formula:
 *   platformFeeAmount = transactionAmount * platformFeePercentage
 *   partnerPayout     = floor((transactionAmount - platformFeeAmount) * partnerSharePercentage, 2)
 *
 * Rounding: floor to the nearest cent (truncate sub-cent fractions) to avoid
 * overpaying partners. This is intentionally NOT round-half-up.
 *
 * @param transactionAmount      - Gross transaction value in dollars (e.g. 100.00)
 * @param platformFeePercentage  - Platform fee as a decimal fraction (e.g. 0.05 for 5%)
 * @param partnerSharePercentage - Partner revenue share as a decimal fraction (e.g. 0.70 for 70%)
 * @returns Partner payout in dollars, floored to 2 decimal places
 *
 * Unspecified edge cases (not in ACs — callers are responsible):
 *   - Negative transactionAmount  → treated as a refund; payout will be negative
 *   - platformFeePercentage > 1.0 → fee exceeds 100%; net amount goes negative
 *   - partnerSharePercentage > 1.0 → partner share exceeds 100%; caller's responsibility
 *   These are left unguarded intentionally: the spec does not define behavior for them,
 *   and adding silent clamps could mask upstream bugs in real payment flows.
 */
export function calculatePartnerPayout(
  transactionAmount: number,
  platformFeePercentage: number,
  partnerSharePercentage: number,
): number {
  const platformFeeAmount = transactionAmount * platformFeePercentage;
  const netAmount = transactionAmount - platformFeeAmount;
  const rawPayout = netAmount * partnerSharePercentage;

  // Floor to nearest cent: multiply by 100, apply Math.floor, divide back.
  // Math.floor handles negative values correctly (floors toward −∞),
  // which matches "avoid overpaying" semantics for positive payouts.
  return Math.floor(rawPayout * 100) / 100;
}

